from collections import defaultdict, deque

class Solution:
    def alienOrder(self, words):
        chars = set(''.join(words))
        graph = {ch: set() for ch in chars}
        indeg = {ch: 0 for ch in chars}
        for a, b in zip(words, words[1:]):
            if len(a) > len(b) and a.startswith(b): return ''
            for x, y in zip(a, b):
                if x != y:
                    if y not in graph[x]: graph[x].add(y); indeg[y] += 1
                    break
        queue = deque(sorted(ch for ch in chars if indeg[ch] == 0))
        out = []
        while queue:
            ch = queue.popleft(); out.append(ch)
            for nxt in sorted(graph[ch]):
                indeg[nxt] -= 1
                if indeg[nxt] == 0: queue.append(nxt)
        return ''.join(out) if len(out) == len(chars) else ''
